class Solution:
    def maximumLengthSubstring(self, s: str) -> int:
        best = 0
        n = len(s)
        for i in range(n):
            freq = {}
            for j in range(i, n):
                c = s[j]
                freq[c] = freq.get(c, 0) + 1
                if freq[c] > 2:
                    break
                best = max(best, j - i + 1)
        return best

