class Solution:
    def maximumLengthSubstring(self, s: str) -> int:
        freq = {}
        left = 0
        best = 0
        for right, c in enumerate(s):
            freq[c] = freq.get(c, 0) + 1
            while freq[c] > 2:
                freq[s[left]] -= 1
                left += 1
            best = max(best, right - left + 1)
        return best

