var maximumLengthSubstring = function(s) {
    const freq = {};
    let left = 0, best = 0;
    for (let right = 0; right < s.length; right++) {
        const c = s[right];
        freq[c] = (freq[c] || 0) + 1;
        while (freq[c] > 2) {
            freq[s[left]]--;
            left++;
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
